'use client';

import { useState } from 'react';
import { addAttendance, updateAttendance, getAttendances, getUsers, getSubjects, getEnrollments, Attendance } from '@/utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { CheckCircle, LogIn, LogOut as LogOutIcon, QrCode } from 'lucide-react';
import { toast } from 'sonner';

type ScanMode = 'in' | 'out';

export default function QRScanner() {
  const [scanMode, setScanMode] = useState<ScanMode>('in');
  const [qrData, setQrData] = useState('');
  const [lastScanned, setLastScanned] = useState<{ studentName: string; subjectName: string; mode: ScanMode } | null>(null);

  const handleScanIn = () => {
    if (!qrData) {
      toast.error('Please enter QR code data');
      return;
    }

    try {
      const [studentId, subjectId] = qrData.split('|');
      const users = getUsers();
      const subjects = getSubjects();
      const enrollments = getEnrollments();
      
      const student = users.find(u => u.id === studentId);
      const subject = subjects.find(s => s.id === subjectId);
      
      if (!student || !subject) {
        toast.error('Invalid QR code data');
        return;
      }

      const enrollment = enrollments.find(e => 
        e.studentId === studentId && 
        e.subjectId === subjectId && 
        e.status === 'approved'
      );

      if (!enrollment) {
        toast.error('Student is not enrolled in this subject');
        return;
      }

      const todayDate = new Date().toISOString().split('T')[0];
      const existingAttendances = getAttendances();
      
      const alreadyScannedIn = existingAttendances.find(a => 
        a.studentId === studentId && 
        a.subjectId === subjectId && 
        a.date.startsWith(todayDate) &&
        a.timeIn
      );

      if (alreadyScannedIn) {
        toast.warning('Student already scanned IN today');
        return;
      }

      const attendance: Attendance = {
        id: `ATT-${Date.now()}`,
        studentId,
        subjectId,
        date: new Date().toISOString(),
        status: 'present',
        timeIn: new Date().toLocaleTimeString('en-US', { hour12: false }),
        sessionId: `SESS-${Date.now()}`
      };

      addAttendance(attendance);
      setLastScanned({ studentName: student.name, subjectName: subject.name, mode: 'in' });
      toast.success(`${student.name} marked PRESENT for ${subject.name}`);
      setQrData('');
    } catch (error) {
      toast.error('Error processing student code');
    }
  };

  const handleScanOut = () => {
    if (!qrData) {
      toast.error('Please enter QR code data');
      return;
    }

    try {
      const [studentId, subjectId] = qrData.split('|');
      const users = getUsers();
      const subjects = getSubjects();
      
      const student = users.find(u => u.id === studentId);
      const subject = subjects.find(s => s.id === subjectId);
      
      if (!student || !subject) {
        toast.error('Invalid QR code data');
        return;
      }

      const todayDate = new Date().toISOString().split('T')[0];
      const existingAttendances = getAttendances();
      
      const todayAttendance = existingAttendances.find(a => 
        a.studentId === studentId && 
        a.subjectId === subjectId && 
        a.date.startsWith(todayDate) &&
        a.timeIn &&
        !a.timeOut
      );

      if (!todayAttendance) {
        toast.error('No matching check-in found for today');
        return;
      }

      updateAttendance(todayAttendance.id, {
        timeOut: new Date().toLocaleTimeString('en-US', { hour12: false })
      });

      setLastScanned({ studentName: student.name, subjectName: subject.name, mode: 'out' });
      toast.success(`${student.name} scanned OUT from ${subject.name}`);
      setQrData('');
    } catch (error) {
      toast.error('Error processing student code');
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 pb-12">
      <div className="text-center py-6">
        <div className="inline-flex h-16 w-16 items-center justify-center bg-primary/10 rounded-2xl mb-4">
          <QrCode className="h-8 w-8 text-primary" />
        </div>
        <h2 className="text-3xl font-black tracking-tight">Attendance Capture</h2>
        <p className="text-muted-foreground font-medium italic">Instant attendance logging via student digital IDs</p>
      </div>

      <Tabs value={scanMode} onValueChange={(v) => setScanMode(v as ScanMode)}>
        <TabsList className="grid w-full grid-cols-2 bg-white border h-14 p-1 rounded-2xl">
          <TabsTrigger value="in" className="rounded-xl data-[state=active]:bg-[#E30613] data-[state=active]:text-white">
            <LogIn className="w-4 h-4 mr-2" />
            Class Entrance (IN)
          </TabsTrigger>
          <TabsTrigger value="out" className="rounded-xl data-[state=active]:bg-[#E30613] data-[state=active]:text-white">
            <LogOutIcon className="w-4 h-4 mr-2" />
            Class Dismissal (OUT)
          </TabsTrigger>
        </TabsList>

        <div className="mt-8">
          <TabsContent value="in">
            <Card className="border-primary/10 shadow-2xl rounded-3xl overflow-hidden">
              <div className="h-2 bg-[#E30613]" />
              <CardHeader className="text-center pb-0 pt-8">
                <CardTitle className="text-2xl font-black">Entrance Scan</CardTitle>
                <CardDescription>Verify student identity at the beginning of the session</CardDescription>
              </CardHeader>
              <CardContent className="p-8 space-y-6">
                <div className="space-y-3">
                  <Label>Scan Input</Label>
                  <Input
                    className="h-14 bg-accent/30 rounded-2xl text-center font-mono"
                    placeholder="ENTER STUDENT CODE DATA"
                    value={qrData}
                    onChange={(e) => setQrData(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleScanIn()}
                  />
                </div>
                <Button 
                  onClick={handleScanIn} 
                  className="w-full h-14 bg-[#E30613] hover:bg-[#E30613]/90 text-white font-black rounded-2xl shadow-xl shadow-[#E30613]/20 text-lg"
                >
                  Confirm Presence
                </Button>

                {lastScanned && lastScanned.mode === 'in' && (
                  <div className="p-6 bg-green-50 border-2 border-green-100 rounded-3xl animate-in slide-in-from-top-4 duration-500">
                    <div className="flex items-center gap-4">
                      <div className="h-12 w-12 rounded-full bg-green-500 flex items-center justify-center">
                        <CheckCircle className="w-6 h-6 text-white" />
                      </div>
                      <div>
                        <p className="font-black text-green-900 uppercase text-xs tracking-widest">Entry Confirmed</p>
                        <p className="text-lg font-bold text-green-800 mt-1">{lastScanned.studentName}</p>
                        <p className="text-xs text-green-600 font-medium">{lastScanned.subjectName}</p>
                      </div>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="out">
            <Card className="border-primary/10 shadow-2xl rounded-3xl overflow-hidden">
              <div className="h-2 bg-[#E30613]" />
              <CardHeader className="text-center pb-0 pt-8">
                <CardTitle className="text-2xl font-black">Exit Scan</CardTitle>
                <CardDescription>Finalize session logs at class dismissal</CardDescription>
              </CardHeader>
              <CardContent className="p-8 space-y-6">
                <div className="space-y-3">
                  <Label>Scan Input</Label>
                  <Input
                    className="h-14 bg-accent/30 rounded-2xl text-center font-mono"
                    placeholder="ENTER STUDENT CODE DATA"
                    value={qrData}
                    onChange={(e) => setQrData(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleScanOut()}
                  />
                </div>
                <Button 
                  onClick={handleScanOut} 
                  className="w-full h-14 bg-[#E30613] hover:bg-[#E30613]/90 text-white font-black rounded-2xl shadow-xl shadow-[#E30613]/20 text-lg"
                >
                  Mark Dismissal
                </Button>

                {lastScanned && lastScanned.mode === 'out' && (
                  <div className="p-6 bg-blue-50 border-2 border-blue-100 rounded-3xl animate-in slide-in-from-top-4 duration-500">
                    <div className="flex items-center gap-4">
                      <div className="h-12 w-12 rounded-full bg-[#E30613] flex items-center justify-center shadow-lg shadow-[#E30613]/20">
                        <CheckCircle className="w-6 h-6 text-white" />
                      </div>
                      <div>
                        <p className="font-black text-primary uppercase text-xs tracking-widest">Exit Logged</p>
                        <p className="text-lg font-bold text-primary/80 mt-1">{lastScanned.studentName}</p>
                        <p className="text-xs text-primary/60 font-medium">{lastScanned.subjectName}</p>
                      </div>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </div>
      </Tabs>
    </div>
  );
}
